mapper.select:
SELECT xk.*, u.username AS user_name, k.coursename AS course_name, CASE xk.status WHEN 1 THEN '进行中' WHEN 2 THEN '已完成' WHEN 3 THEN '已放弃' ELSE '未知' END AS status_text FROM selection xk LEFT JOIN student u ON xk.user_id = u.id LEFT JOIN course k ON xk.course_id = k.id
AND xk.id = #{id}
AND xk.user_id = #{userId}
AND xk.course_id = #{courseId}
AND xk.status = #{status}

mapper.update:
UPDATE selection
SET
    progress = #{progress},
    last_learn_time = #{lastLearnTime, jdbcType=TIMESTAMP},
    status = #{status}
WHERE id = #{id}
